// Worked focus: http-ts-bounded-response-reads — Limit compressed and decoded response reads before allocation, parsing, logging, or persistence. Demonstrate the result through TypeScript 7 strict types plus WHATWG Fetch Request, Response, Headers, URL, streams, and AbortSignal contracts.
function worked_http_ts_body_streams_limits_3(compressedBytes: number, decodedBytes: number, maximumDecodedBytes: number): { accepted: boolean; expansionRatio: number } {
  if (compressedBytes <= 0 || decodedBytes < 0 || maximumDecodedBytes <= 0) {
    return { accepted: false, expansionRatio: Number.POSITIVE_INFINITY };
  }
  const expansionRatio = decodedBytes / compressedBytes;
  return { accepted: decodedBytes <= maximumDecodedBytes && expansionRatio <= 100, expansionRatio };
}

